        },
        {
          "IsNull": false,
          "Modified": true,
          "Name": "PMTCode",
          "Value": "M"
        },
        {
          "IsNull": false,
          "Modified": true,
          "Name": "ProductCode",
          "Value": "FG-100"
        },
        {
          "IsNull": false,
          "Modified": true,
          "Name": "AbcCode",
          "Value": "B"
        },
        {
          "IsNull": false,
          "Modified": true,
          "Name": "CostType",
          "Value": "A"
        },
        {
          "IsNull": false,
